<# .SYNOPSIS Offline decision-matrix regression for the evidence market. #>
param([switch]$PassThru)
$ErrorActionPreference='Stop';$root=(Resolve-Path(Join-Path $PSScriptRoot '..\..')).Path;$path=Join-Path $root '.qianlima\tmp\evidence-market-test.json';New-Item -ItemType Directory -Path(Split-Path $path)-Force|Out-Null;$evaluator=Join-Path $PSScriptRoot 'evaluate-evidence-market.ps1'
function Eval($disagreement,$strength,$supplementable,$sources=@('source:1')){$x=[ordered]@{fusion_id='fusion-test';claim_pack_refs=@('claim:a','claim:b');source_refs=$sources;producer_id='candidate-a';verifier_id='independent-checker';adversarial_checker_id='adversarial-checker';evidence_strength=$strength;sources_traceable=($sources.Count-gt0);falsifiers_present=$true;disagreement_level=$disagreement;supplementable=$supplementable};[IO.File]::WriteAllText($path,($x|ConvertTo-Json -Depth 6),[Text.UTF8Encoding]::new($false));$out=& powershell.exe -NoProfile -ExecutionPolicy Bypass -File $evaluator -InputPath $path -PassThru 2>&1;[pscustomobject]@{code=$LASTEXITCODE;text=($out-join"`n")}}
$cases=[System.Collections.Generic.List[object]]::new();$a=Eval low .9 $false;$b=Eval low .3 $false;$c=Eval high .8 $true;$d=Eval high .8 $false;$e=Eval low .9 $false @();$cases.Add([pscustomobject]@{name='low_strong_verified';passed=($a.text-match'verified')});$cases.Add([pscustomobject]@{name='low_weak_low_confidence';passed=($b.text-match'low_confidence')});$cases.Add([pscustomobject]@{name='high_supplementable_requests_evidence_without_grant';passed=($c.text-match'evidence_required'-and$c.text-match'"additional_budget_granted":\s+false')});$cases.Add([pscustomobject]@{name='high_unsupplementable_needs_human';passed=($d.text-match'needs_human')});$cases.Add([pscustomobject]@{name='agreement_without_sources_rejected';passed=($e.code-ne0)});$failed=@($cases|?{-not$_.passed});$result=[pscustomobject]@{passed=($failed.Count-eq0);cases=@($cases);external_calls=$false;permissions_granted=$false};if($PassThru){$result|ConvertTo-Json -Depth 6}else{$cases|Format-Table -AutoSize};if($failed.Count){throw('Evidence market regression failed: '+(($failed.name)-join', '))}
